import{_ as t,o as a,c as o,ae as i}from"./chunks/framework.CbfcRfVi.js";const n="/playstation-linux-tutorial/screenshots/system-info.png",s="/playstation-linux-tutorial/screenshots/payload-server-conf.png",l="/playstation-linux-tutorial/screenshots/settings-sound-and-screen.png",r="/playstation-linux-tutorial/screenshots/resolution.png",u="/playstation-linux-tutorial/screenshots/rgb-range.png",d="/playstation-linux-tutorial/screenshots/settings-system.png",h="/playstation-linux-tutorial/screenshots/hdcp-and-device-link.png",S=JSON.parse('{"title":"Requirements and initial setup","description":"","frontmatter":{},"headers":[],"relativePath":"ps4/setup.md","filePath":"ps4/setup.md","lastUpdated":1777872142000}'),c={name:"ps4/setup.md"};function p(m,e,y,b,g,f){return a(),o("div",null,[...e[0]||(e[0]=[i('<h1 id="requirements-and-initial-setup" tabindex="-1">Requirements and initial setup <a class="header-anchor" href="#requirements-and-initial-setup" aria-label="Permalink to &quot;Requirements and initial setup&quot;">​</a></h1><p>In order to install Linux on the PS4, a lot of things are needed. You may have to buy some gear to make this work.</p><h2 id="requirements" tabindex="-1">Requirements <a class="header-anchor" href="#requirements" aria-label="Permalink to &quot;Requirements&quot;">​</a></h2><p>You&#39;ll need:</p><ul><li>Preferably an extra mouse and keyboard, but the main ones you use are fine as well</li><li>A USB hub to connect all the peripherals is recommended</li><li>A computer</li><li>An internet connection</li><li>(Optional) - one or more USB drives <ul><li>If you want to install to an external drive, you can use a USB pendrive or HDD, but it&#39;s recommend to have a SATA SSD and a SATA to USB adapter (preferably one that supports UAS).</li></ul></li></ul><h2 id="storage-devices-to-install-to" tabindex="-1">Storage devices to install to <a class="header-anchor" href="#storage-devices-to-install-to" aria-label="Permalink to &quot;Storage devices to install to&quot;">​</a></h2><p>Before starting, you need to choose method of installation.</p><ol><li>Internal HDD <ul><li>Baikal still unsupported, very slow, needs free space</li></ul></li><li>External HDD/SSD <ul><li>External USB Hard Disk Drive or USB Solid State Drive. Use a USB 3.x capable disk and cable for the best performance</li><li>External SATA-USB or NVMe-USB adapter (if using a SATA/NVMe drive)</li><li>You can use a pendrive, but I highly advise <strong>NOT</strong> to because of the slow speeds.</li></ul></li></ol><h2 id="ps4-system" tabindex="-1">PS4 system <a class="header-anchor" href="#ps4-system" aria-label="Permalink to &quot;PS4 system&quot;">​</a></h2><p>Some configuration is necessary on the PS4&#39;s side before we load Linux.</p><h3 id="things-to-note-down" tabindex="-1">Things to note down <a class="header-anchor" href="#things-to-note-down" aria-label="Permalink to &quot;Things to note down&quot;">​</a></h3><p>Note down what you see in &quot;Settings -&gt; System Information&quot;:</p><ul><li>System software version</li><li>Southbridge</li><li>Your GoldHEN or ps4hen version</li></ul><img src="'+n+'" width="75%"><p>In the example case, the latest version of GoldHEN is used (minimum for this guide is v2.4b18.5), running on a Belize PS4 Slim.</p><h3 id="hen" tabindex="-1">HEN <a class="header-anchor" href="#hen" aria-label="Permalink to &quot;HEN&quot;">​</a></h3><p>You need a system that is already jailbroken and has a homebrew enabler (such as GoldHEN or ps4hen) running.</p><div class="tip custom-block github-alert"><p class="custom-block-title">TIP</p><p>To jailbreak your PS4, you need firmware 13.02 or lower</p><p>Refer to <a href="https://www.youtube.com/@MODDEDWARFARE" target="_blank" rel="noreferrer">Modded Warfare</a> on YouTube if you haven&#39;t already.</p></div><p>In order to input text on your PS4, you can&#39;t use the PS4 built in keyboard, as that is not available on Linux. You must have a keyboard and mouse combo ready to use with your PS4.</p><h4 id="payload-server-settings" tabindex="-1">Payload server settings <a class="header-anchor" href="#payload-server-settings" aria-label="Permalink to &quot;Payload server settings&quot;">​</a></h4><p>Remember to check the GoldHEN &quot;Server&quot; settings (or ps4hen&#39;s equivalent if you&#39;re using that) so that they are both enabled:</p><img src="'+s+'" width="75%"><p>These are required to be able to move files and load Linux later into the guide.</p><h3 id="settings" tabindex="-1">Settings <a class="header-anchor" href="#settings" aria-label="Permalink to &quot;Settings&quot;">​</a></h3><p>These need to be taken as a precaution, not as a necessity, as they aren&#39;t actually needed anymore. However, as some issues may arise on certain consoles, you should still go and tweak these settings.</p><h4 id="audio-and-display-settings" tabindex="-1">&quot;Audio and Display&quot; settings <a class="header-anchor" href="#audio-and-display-settings" aria-label="Permalink to &quot;&quot;Audio and Display&quot; settings&quot;">​</a></h4><h5 id="resolution" tabindex="-1">Resolution <a class="header-anchor" href="#resolution" aria-label="Permalink to &quot;Resolution&quot;">​</a></h5><img src="'+l+'" width="75%"><img src="'+r+'" width="75%"><ul><li>Set your resolution to 1080p (or 720p) <ul><li>4K may not work on PS4 Pro. Try 1080p first.</li><li>Not always required? Works on Belize in Automatic.</li></ul></li></ul><h5 id="rgb-color-gamut" tabindex="-1">RGB Color gamut <a class="header-anchor" href="#rgb-color-gamut" aria-label="Permalink to &quot;RGB Color gamut&quot;">​</a></h5><img src="'+u+'" width="75%"><ul><li>Set your RGB color gamut <ul><li>It may be automatically set to &quot;Limited&quot; even if your display supports &quot;Full&quot;.</li><li>&quot;Full&quot; may not work on really old displays. If the image looks weird, set it to &quot;Limited&quot;.</li></ul></li></ul><h4 id="system-settings" tabindex="-1">&quot;System&quot; settings <a class="header-anchor" href="#system-settings" aria-label="Permalink to &quot;&quot;System&quot; settings&quot;">​</a></h4><img src="'+d+'" width="75%"><img src="'+h+'" width="75%"><ul><li>Check your internet connection <ul><li>Some models have issues if they aren&#39;t already connected to the internet.</li><li>Ethernet may not work on PS4 Pro Baikal</li></ul></li></ul><h2 id="pc" tabindex="-1">PC <a class="header-anchor" href="#pc" aria-label="Permalink to &quot;PC&quot;">​</a></h2><p>A way to connect to your PS4 to transfer files is needed. A PC is recommended. You will also need an internet connection.</p><p>You&#39;ll be accessing your PS4&#39;s filesystem via FTP. You can also transfer files with a USB drive if you feel so inclined.</p><h3 id="ftp-connections" tabindex="-1">FTP connections <a class="header-anchor" href="#ftp-connections" aria-label="Permalink to &quot;FTP connections&quot;">​</a></h3><p>In order to do that, open up your FTP file manager of choice.</p><h4 id="windows" tabindex="-1">Windows <a class="header-anchor" href="#windows" aria-label="Permalink to &quot;Windows&quot;">​</a></h4><ul><li>The built-in Windows File Explorer <ul><li>This one likes to crash the desktop if it can&#39;t connect, be careful</li></ul></li><li>WinSCP (recommended, using the simple interface)</li><li>Filezilla</li></ul><h4 id="linux" tabindex="-1">Linux <a class="header-anchor" href="#linux" aria-label="Permalink to &quot;Linux&quot;">​</a></h4><ul><li>Built in File explorer, if yours allows it.</li><li>Filezilla</li></ul><h4 id="macos" tabindex="-1">MacOS <a class="header-anchor" href="#macos" aria-label="Permalink to &quot;MacOS&quot;">​</a></h4><ul><li>Filezilla</li></ul>',48)])])}const P=t(c,[["render",p]]);export{S as __pageData,P as default};
